import random, math
from math import gcd

def lcm(a,b):
    return a*b//gcd(a,b)

def move(board, i, j):
    m, n = board[i], board[j]
    g = gcd(m,n)
    l = lcm(m,n)//g
    board[i] = g
    board[j] = l
    return board

def run_random(board, verbose=False):
    board = board[:]
    steps = 0
    while True:
        idxs = [i for i,v in enumerate(board) if v>1]
        if len(idxs) <= 1:
            break
        i,j = random.sample(idxs, 2)
        move(board, i, j)
        steps += 1
        if steps > 10000:
            raise Exception("too many steps")
    survivors = [v for v in board if v>1]
    return survivors, steps

def expected_M(board):
    # product over primes p of p^(max exponent across board)
    from sympy import factorint
    maxexp = {}
    for x in board:
        f = factorint(x)
        for p,e in f.items():
            maxexp[p] = max(maxexp.get(p,0), e)
    M = 1
    for p,e in maxexp.items():
        M *= p**e
    return M

